import React from 'react';
import { X } from 'lucide-react';
import OptimizationActionChip from './OptimizationActionChip';
import ConfidenceScore from './ConfidenceScore';
import { formatCurrency } from '../../utils/format';
import { workflowStatusLabel } from '../../utils/actionUtils';
import { resourceGroupLabelForAction } from '../../utils/optimizationGrouping';

export default function ActionDetailDrawer({
  action,
  currency = 'USD',
  onClose,
  onApproveClick,
  isAdmin = false,
}) {
  if (!action) return null;

  const advisorFinding = action.advisor_finding ? (
    typeof action.advisor_finding === 'string'
      ? JSON.parse(action.advisor_finding)
      : action.advisor_finding
  ) : null;

  const costEvidence = action.cost_evidence ? (
    typeof action.cost_evidence === 'string'
      ? JSON.parse(action.cost_evidence)
      : action.cost_evidence
  ) : null;

  const utilizationEvidence = action.utilization_evidence ? (
    typeof action.utilization_evidence === 'string'
      ? JSON.parse(action.utilization_evidence)
      : action.utilization_evidence
  ) : null;

  const decisionRules = action.decision_rules_applied ? (
    typeof action.decision_rules_applied === 'string'
      ? JSON.parse(action.decision_rules_applied)
      : action.decision_rules_applied
  ) : [];

  return (
    <div className="action-detail-drawer-overlay" role="presentation" onClick={onClose}>
      <div
        className="action-detail-drawer"
        role="dialog"
        aria-labelledby="action-detail-title"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <header className="action-detail-drawer__header">
          <div>
            <h2 id="action-detail-title" className="action-detail-drawer__title">
              {action.resource_name}
            </h2>
            <p className="action-detail-drawer__subtitle">
              {action.resource_type} • {action.resource_group || resourceGroupLabelForAction(action)}
            </p>
          </div>
          <button
            type="button"
            className="btn-icon"
            onClick={onClose}
            aria-label="Close"
          >
            <X size={20} />
          </button>
        </header>

        {/* Content */}
        <div className="action-detail-drawer__body">
          {/* Quick summary */}
          <section className="drawer-section">
            <h3 className="drawer-section__title">Action summary</h3>
            <div className="drawer-summary-grid">
              <div className="drawer-summary-item">
                <span className="drawer-summary-label">Type</span>
                <div className="drawer-summary-value">
                  <OptimizationActionChip actionType={action.action_type} />
                </div>
              </div>
              <div className="drawer-summary-item">
                <span className="drawer-summary-label">Confidence</span>
                <div className="drawer-summary-value">
                  <ConfidenceScore confidence={action.confidence} compact />
                </div>
              </div>
              <div className="drawer-summary-item">
                <span className="drawer-summary-label">Status</span>
                <div className="drawer-summary-value">
                  <span className="workflow-pill">
                    {workflowStatusLabel(action.workflow_status)}
                  </span>
                </div>
              </div>
              {action.estimated_monthly_savings > 0 && (
                <div className="drawer-summary-item">
                  <span className="drawer-summary-label">Est. savings/mo</span>
                  <div className="drawer-summary-value text-highlight">
                    {formatCurrency(action.estimated_monthly_savings, { currency })}
                  </div>
                </div>
              )}
            </div>
          </section>

          {/* Action reason */}
          {action.action_reason && (
            <section className="drawer-section">
              <h3 className="drawer-section__title">Recommendation</h3>
              <p className="drawer-section-text">{action.action_reason}</p>
            </section>
          )}

          {/* Investigations section */}
          <section className="drawer-section">
            <h3 className="drawer-section__title">Investigations</h3>

            {/* Azure Advisor finding */}
            {advisorFinding && Object.keys(advisorFinding).length > 0 && (
              <div className="drawer-investigation">
                <h4 className="drawer-investigation__title">Azure Advisor</h4>
                {advisorFinding.recommendation && (
                  <p className="drawer-investigation-text">
                    {advisorFinding.recommendation}
                  </p>
                )}
                {advisorFinding.impact && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Impact:</span>
                    <span>{advisorFinding.impact}</span>
                  </div>
                )}
                {advisorFinding.savings && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Savings:</span>
                    <span>{formatCurrency(advisorFinding.savings, { currency })}/mo</span>
                  </div>
                )}
              </div>
            )}

            {/* Cost evidence */}
            {costEvidence && Object.keys(costEvidence).length > 0 && (
              <div className="drawer-investigation">
                <h4 className="drawer-investigation__title">Cost signals</h4>
                {costEvidence.metric && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Metric:</span>
                    <span>{costEvidence.metric}</span>
                  </div>
                )}
                {costEvidence.current_cost && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Current monthly cost:</span>
                    <span>{formatCurrency(costEvidence.current_cost, { currency })}</span>
                  </div>
                )}
                {costEvidence.estimated_savings && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Est. savings:</span>
                    <span className="text-highlight">
                      {formatCurrency(costEvidence.estimated_savings, { currency })}
                    </span>
                  </div>
                )}
              </div>
            )}

            {/* Utilization evidence */}
            {utilizationEvidence && Object.keys(utilizationEvidence).length > 0 && (
              <div className="drawer-investigation">
                <h4 className="drawer-investigation__title">Utilization metrics</h4>
                {utilizationEvidence.metric && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Metric:</span>
                    <span>{utilizationEvidence.metric}</span>
                  </div>
                )}
                {utilizationEvidence.average && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Average:</span>
                    <span>{utilizationEvidence.average}%</span>
                  </div>
                )}
                {utilizationEvidence.peak && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Peak:</span>
                    <span>{utilizationEvidence.peak}%</span>
                  </div>
                )}
                {utilizationEvidence.trend && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Trend:</span>
                    <span>{utilizationEvidence.trend}</span>
                  </div>
                )}
              </div>
            )}

            {/* Decision rules */}
            {Array.isArray(decisionRules) && decisionRules.length > 0 && (
              <div className="drawer-investigation">
                <h4 className="drawer-investigation__title">Decision rules applied</h4>
                <ul className="drawer-rules-list">
                  {decisionRules.map((rule, idx) => (
                    <li key={idx} className="drawer-rules-item">
                      {typeof rule === 'string' ? rule : rule.name || JSON.stringify(rule)}
                    </li>
                  ))}
                </ul>
              </div>
            )}

            {!advisorFinding && !costEvidence && !utilizationEvidence && decisionRules.length === 0 && (
              <p className="text-muted text-sm">No investigation details available</p>
            )}
          </section>
        </div>

        {/* Footer with action buttons */}
        <footer className="action-detail-drawer__footer">
          <button
            type="button"
            className="btn btn--ghost"
            onClick={onClose}
          >
            Close
          </button>
          {isAdmin && (
            <button
              type="button"
              className="btn btn--primary"
              onClick={onApproveClick}
            >
              Approve/Update
            </button>
          )}
        </footer>
      </div>
    </div>
  );
}
